const b = $input.first().json.body || $input.first().json;
const phone = (b.From || b.from || b.phone || '').replace('whatsapp:','').trim();
const message = (b.Body || b.body || b.message || b.text || '').trim();

// ✏️ CAMBIA ESTE ID cuando crees tu barbería real
const BARBERSHOP_ID = 'TU_BARBERSHOP_ID';
const BASE = 'https://eslygfjpxwrjnoimsrly.supabase.co';
const KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVzbHlnZmpweHdyam5vaW1zcmx5Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3Nzg1ODE0MCwiZXhwIjoyMDkzNDM0MTQwfQ.zTMI8PjaF6L785B69zRUDeEqPcYz4LE1DrYo-7tpaP0';
const TODAY = new Date().toISOString().split('T')[0];
const D7 = new Date(Date.now() + 7*864e5).toISOString().split('T')[0];

return [{ json: {
  phone, message, barbershop_id: BARBERSHOP_ID, today: TODAY, base: BASE, key: KEY,
  appts_url: `${BASE}/rest/v1/appointments?barbershop_id=eq.${BARBERSHOP_ID}&appointment_date=gte.${TODAY}&appointment_date=lte.${D7}&status=in.(scheduled,confirmed,pending)&select=appointment_date,start_time,end_time,barbers(name),services(name,duration_minutes)&order=appointment_date.asc,start_time.asc&limit=20`,
  svcs_url: `${BASE}/rest/v1/services?barbershop_id=eq.${BARBERSHOP_ID}&select=name,duration_minutes,price&order=name.asc`
}}];

const cfg = $('📝 Extraer + Configurar').item.json;
const appts = $('📅 Citas próximas (Supabase)').item.json;
const svcs = $('✂️ Servicios (Supabase)').item.json;

const apptsList = Array.isArray(appts) ? appts : [];
const svcsList = Array.isArray(svcs) ? svcs : [];

const aptsSummary = apptsList.length === 0
  ? 'No hay citas reservadas los próximos 7 días.'
  : apptsList.map(a => `- ${a.appointment_date} ${a.start_time?.slice(0,5)}-${a.end_time?.slice(0,5)} | ${a.barbers?.name || 'Barbero'} | ${a.services?.name || 'Servicio'}`).join('\n');

const svcsSummary = svcsList.map(s => `- ${s.name} (${s.duration_minutes} min, ${s.price}€)`).join('\n') || 'Sin servicios configurados.';

const systemPrompt = `Eres el asistente virtual de reservas de la barbería. Respondes por WhatsApp en español, de forma amable y concisa.

CITAS RESERVADAS PRÓXIMAS 7 DÍAS:\n${aptsSummary}\n\nSERVICIOS DISPONIBLES:\n${svcsSummary}\n\nINSTRUCCIONES:\n- Ayuda al cliente a reservar cita o resolver dudas\n- Si quiere reservar, indícale los huecos disponibles entre las citas ya existentes (horario 09:00-20:00)\n- Siempre termina con el link de reserva: https://barberiaos.com/r/${cfg.barbershop_id}\n- Máximo 3 líneas de respuesta\n- Si no hay hueco para su horario, sugiere el más cercano disponible`;

return [{ json: {
  phone: cfg.phone,
  barbershop_id: cfg.barbershop_id,
  openai_key: 'TU_OPENAI_API_KEY',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: cfg.message }
  ]
}}];

const phone = $('🧠 Construir prompt OpenAI').item.json.phone;
const raw = $input.first().json;
const reply = raw.choices?.[0]?.message?.content || 'Lo siento, no pude procesar tu mensaje. Llámanos directamente.';
return [{ json: { phone, reply, ts: new Date().toISOString() } }];
